patch:
diff --git a/llvm/lib/Transforms/Scalar/GVN.cpp b/llvm/lib/Transforms/Scalar/GVN.cpp
index 4baa3b3eb824..5f7cce3dce50 100644
--- a/llvm/lib/Transforms/Scalar/GVN.cpp
+++ b/llvm/lib/Transforms/Scalar/GVN.cpp
@@ -2790,6 +2790,9 @@ bool GVNPass::processInstruction(Instruction *I) {
   // no point in trying to find redundancies in them.
   if (I->getType()->isVoidTy())
     return false;
+  // Token-like and metadata types cannot be used in PHI nodes, so skip them.
+  if (I->getType()->isTokenLikeTy() || I->getType()->isMetadataTy())
+    return false;

   uint32_t NextNum = VN.getNextUnusedValueNumber();
   unsigned Num = VN.lookupOrAdd(I);
@@ -2800,8 +2803,6 @@ bool GVNPass::processInstruction(Instruction *I) {
     LeaderTable.insert(Num, I, I->getParent());
     return false;
   }
-
-  // If the number we were assigned was a brand new VN, then we don't
   // need to do a lookup to see if the number already exists
   // somewhere in the domtree: it can't!
   if (Num >= NextNum) {
@@ -2980,6 +2981,8 @@ bool GVNPass::performScalarPREInsertion(Instruction *Instr, BasicBlock *Pred,
 }

 bool GVNPass::performScalarPRE(Instruction *CurInst) {
+  if (CurInst->getType()->isTokenLikeTy() || CurInst->getType()->isMetadataTy())
+    return false;
   if (isa<AllocaInst>(CurInst) || CurInst->isTerminator() ||
       isa<PHINode>(CurInst) || CurInst->getType()->isVoidTy() ||
       CurInst->mayReadFromMemory() || CurInst->mayHaveSideEffects())

